(window.webpackJsonp=window.webpackJsonp||[]).push([[38],{665:function(n,e){n.exports='\x3c!-- \ntitle: GithubAction\nsort: \n--\x3e \n\n```yml\non :\n  push:\n    branches:\n    # 指定分支\n    - master\n    # 指定路径\n    paths:\n    - *\njobs:\n  job1:\n    runs-on:ubuntu-latest\n  steps:\n  - uses:actions/checkout@v2\n  - uses:actions/setup-node@v1\n  with:\n  - node-version: ${{ env.NODE_VERSION }}\n  - run: |\n      npm install\n      npm run build--if-present\n      npm test\n```\n\n## Hexo\n\n```bash\n# 生成ssh密钥\nssh-keygen -f github-deploy-key\n# 将公私钥分别复制到静态界面仓库-配置仓库\nrepository->setting->secrets\nrepository->setting->\n\n# 创建Action配置文件\nblog (repository)\n└── .github\n    └── workflows\n        └── deploy.yml\n```\n\n> `deploy.yml`\n\n```yml\nname: HEXO_DEPLOY\n\non:\n  push:\n    branches:\n      - master\n\nenv:\n  GIT_USER: fzf404\n  GIT_EMAIL: nmdfzf404@163.com\n\njobs:\n  build:\n    runs-on: ubuntu-latest\n\n    steps:\n      - name: Checkout source\n        uses: actions/checkout@v2\n\n      - name: Use Node.js ${{ matrix.node_version }}\n        uses: actions/setup-node@v1\n        with:\n          version: ${{ matrix.node_version }}\n\n      - name: Setup hexo\n        env:\n          ACTION_DEPLOY_KEY: ${{ secrets.HEXO_DEPLOY_PRI }}\n\n        run: |\n          sudo timedatectl set-timezone "Asia/Shanghai"\n          mkdir -p ~/.ssh/\n          echo "$ACTION_DEPLOY_KEY" > ~/.ssh/id_rsa\n          chmod 600 ~/.ssh/id_rsa\n          ssh-keyscan github.com >> ~/.ssh/known_hosts\n          git config --global user.email $GIT_USER\n          git config --global user.name $GIT_EMAIL\n          npm install hexo-cli -g\n          npm install\n      - name: Hexo deploy\n        run: |\n          hexo clean\n          hexo d\n```\n\n> 拷贝hexo配置\n\n```\nthemes\n_config.yml\npackage.json\n```\n\n> 上传github\n\n```yml\ngit remote add origin git@github.com:xx/xx.git\ngit branch -M master\ngit push -u origin master\n```\n\n## 成功\n\n![image-20201204162421362](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201204162428.png)\n\n'}}]);